using BotFramework.Host.Execution;
namespace Games.Pick.Application.Execution;
public sealed class DailyBuyDescriptor:GameExecutionDescriptor<DailyBuyCommand,DailyLotteryState,DailyBuyResult>
{public override string GameId=>"pick-daily";public override string CommandId(DailyBuyCommand c)=>c.CommandId;public override string AggregateId(DailyBuyCommand c)=>$"{c.ChatId}:{c.DayLocal:yyyy-MM-dd}";public override long ChatId(DailyBuyCommand c)=>c.ChatId;public override string DisplayName(DailyBuyCommand c)=>c.DisplayName;public override WalletIdentity Wallet(DailyBuyCommand c)=>new(c.UserId,c.ChatId);}
public sealed class DailySettleDescriptor:GameExecutionDescriptor<DailySettleCommand,DailyLotteryState,DailySettleResult>
{public override string GameId=>"pick-daily";public override bool UsesPrimaryWallet=>false;public override IReadOnlyList<string> EntropyNames=>[DailySettleAction.WinnerEntropy];public override string CommandId(DailySettleCommand c)=>c.CommandId;public override string AggregateId(DailySettleCommand c)=>$"{c.Row.ChatId}:{c.Row.DayLocal:yyyy-MM-dd}";public override long ChatId(DailySettleCommand c)=>c.Row.ChatId;public override string DisplayName(DailySettleCommand c)=>"daily lottery";public override WalletIdentity Wallet(DailySettleCommand c)=>new(0,c.Row.ChatId);public override IReadOnlyList<string> AdditionalLockKeys(DailySettleCommand c)=>c.ExpectedTickets.Select(x=>new WalletIdentity(x.UserId,c.Row.ChatId).LockKey).Distinct().ToArray();}
